import { useState } from "react";
import "./styles.css";

const initialTasks = [
  { id: 1, name: "Оновити ядро Arch Linux", completed: true },
  { id: 2, name: "Налаштувати кольори Waybar", completed: false },
  { id: 3, name: "Зробити бекап дотфайлів", completed: false },
];

export default function TaskManager() {
  const [tasks, setTasks] = useState(initialTasks);

  function toggleTask(clickedId) {}

  return (
    <div className="app-container">
      <h1>Менеджер завдань</h1>
      <div className="task-list">
        {tasks.map((task) => (
          <div
            key={task.id}
            className={`task ${task.completed ? "done" : "pending"}`}

            // 3. ТУТ ТВІЙ КОД:
            // Додай подію onClick до цього div.
            // При кліку вона має викликати функцію toggleTask і передати їй task.id
            // Підказка: оскільки ми передаємо параметр (task.id), нам треба
            // використати стрілочну функцію всередині onClick: () => ...
          >
            <p>{task.name}</p>
          </div>
        ))}
      </div>
    </div>
  );
}
